INSERT OR IGNORE INTO 'issues'('id', 'slug', 'title', 'description', 'issue_type', 'status', 'is_blocked', 'priority', 'failure_count', 'current_task_id', 'worktree_path', 'parent_issue_id', 'stuck_previous_status', 'stuck_reason', 'investigation_result', 'stuck_at', 'estimated_lines', 'test_passed', 'test_duration_seconds', 'merged_to_master', 'human_accepted', 'human_accepted_at', 'nitpick_result', 'created_at', 'updated_at') VALUES (106, 'ISSUE-A003b', '用户资料管理 - 移动端 API Client 层', replace('在移动端封装统一的用户资料 API 调用层，依赖后端 ISSUE-A003a 的接口。\n\n目标：给 A003c（移动端 UI）提供稳定的数据访问接口。\n\n实现内容：\n- 创建 apps/mobile/src/api/user/ 目录结构\n- 封装 userService 相关 API：\n  - GET/PUT /api/v1/users/me（用户资料读写）\n  - POST /api/v1/users/avatar（头像上传）\n  - POST/PUT /api/v1/users/privacy（隐私设置读写）\n  - POST /api/v1/users/password（修改密码）\n  - POST /api/v1/users/phone（手机绑定）\n  - POST /api/v1/users/email（邮箱绑定）\n  - GET/DELETE /api/v1/users/devices（设备管理）\n  - GET/POST/DELETE /api/v1/users/block（黑名单管理）\n- 统一错误处理、Loading 状态、TypeScript 类型定义\n- 依赖 apps/server/src/routes/users.ts、userPrivacy.ts 中的接口（已在 A003a 实现）\n\n技术栈：TypeScript、Fetch/axios、统一类型定义\n\n验收标准：\n- [ ] 所有用户资料相关 API 均有封装函数\n- [ ] TypeScript 类型与后端接口字段一致\n- [ ] 错误处理统一（网络错误、业务错误分类）\n- [ ] A003c 可直接调用本层 API 完成 UI 对接','\n', char(10)), 'implement', 'implemented', 1, 1, 0, NULL, NULL, 5, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-04-18 12:18:20', '2026-04-19 09:01:27.503621');
INSERT OR IGNORE INTO 'issues'('id', 'slug', 'title', 'description', 'issue_type', 'status', 'is_blocked', 'priority', 'failure_count', 'current_task_id', 'worktree_path', 'parent_issue_id', 'stuck_previous_status', 'stuck_reason', 'investigation_result', 'stuck_at', 'estimated_lines', 'test_passed', 'test_duration_seconds', 'merged_to_master', 'human_accepted', 'human_accepted_at', 'nitpick_result', 'created_at', 'updated_at') VALUES (107, 'ISSUE-A003c', '用户资料管理 - 移动端 UI 对接', replace('将移动端所有设置页面的 stub/TODO 替换为真实 API 调用，依赖移动端 API Client 层（ISSUE-A003b）。\n\n目标：用户可在 App 内完成完整的个人资料管理。\n\n实现内容（按页面）：\n- EditProfileScreen：头像上传替换 stub、基本信息编辑\n- SecuritySettingsScreen：密码修改、手机绑定、邮箱绑定、登录设备管理、删除账号\n- PrivacySettingsScreen：隐私设置读写、阻止用户列表、添加/移除黑名单\n- DisclosureSettings：信息披露设置（对接 Agent 相关披露规则）\n\n技术栈：React Native、Zustand/React Query、依赖 A003b 的 API 封装层\n\n验收标准：\n- [ ] EditProfileScreen 头像上传正常（选图 → 上传 → 预览）\n- [ ] SecuritySettingsScreen 所有功能正常（密码/手机/邮箱/设备/注销）\n- [ ] PrivacySettingsScreen 隐私设置和黑名单功能正常\n- [ ] DisclosureSettings 信息披露设置正常\n- [ ] 所有页面无 stub、无 TODO','\n', char(10)), 'implement', 'stuck', 1, 1, 1, NULL, NULL, 5, 'implemented', 'start_failed', NULL, '2026-04-19 06:38:00.021550', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-04-18 12:18:30', '2026-04-19 06:38:00.021552');
