INSERT OR IGNORE INTO 'issues'('id', 'slug', 'title', 'description', 'issue_type', 'status', 'is_blocked', 'priority', 'failure_count', 'current_task_id', 'worktree_path', 'parent_issue_id', 'stuck_previous_status', 'stuck_reason', 'investigation_result', 'stuck_at', 'estimated_lines', 'test_passed', 'test_duration_seconds', 'merged_to_master', 'human_accepted', 'human_accepted_at', 'nitpick_result', 'created_at', 'updated_at') VALUES (86, 'ISSUE-T004', 'E2E端到端测试框架', replace('搭建端到端(E2E)测试框架，采用Detox + Maestro双层架构。\n\n**生产层(Detox)**: 使用Detox进行稳定可靠的移动端E2E测试，覆盖完整的用户操作流程。包括测试环境配置、测试数据准备、页面对象模式、测试报告等。确保整个系统从前端到后端的完整流程正常工作。\n\n**探索层(Maestro)**: 使用YAML声明式的Maestro测试框架，专为AI Agent自动化设计。支持快速验证新功能，AI可直接生成测试脚本。验证通过后再迁移到Detox生产套件。\n\n**严格标准要求**:\n- 测试稳定性: Flaky rate < 2%\n- 执行效率: 单测试≤2分钟，全套件≤15分钟(并行)\n- 测试隔离: 100%测试独立，无状态依赖\n- 断言密度: 每流程≥5个关键断言\n- 覆盖率: 核心用户流程≥90%','\n', char(10)), 'implement', 'implemented', 1, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-04-14 15:16:44.160015', '2026-04-19 09:01:27.502620');
