INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (680, 'US-AGENT-010~func', 49, '双方真人交流后互相评分，影响信用分', 'functional', '## 前置准备\n- 完成任意场景的四人群聊交流（DATE-004 或 JOB-004）\n\n## 验收步骤\n1. 交流结束后弹出评分界面\n2. 多维度评分：诚信度、礼貌度、响应度、满意度（1-5星）\n3. 提交评分\n4. 验证：信用分根据评分变化\n5. 用另一账号评分，确认双向评分\n\n## 人类质询点\n- 评分后信用分变化是否合理？\n- 各维度评分的说明是否清楚？\n- 不评分能继续使用 App 吗？', 1, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (681, 'US-AGENT-010~edge', 49, '异常：恶意评分、重复评分', 'edge_case', '1. 尝试给同一人连续打最低分，是否触发反作弊\n2. 对同一次交流评分两次，应阻止\n3. 未进行任何交流就尝试评分，应不允许', 2, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (682, 'US-AGENT-013~func', 50, '通过 Agent 浏览对方的公开需求和供给', 'functional', '## 前置准备\n- 完成 US-AGENT-002\n- 多个测试账号已配置需求/供给\n\n## 验收步骤\n1. 进入浏览页面\n2. Agent 展示对方的公开需求和供给概要\n3. 验证：只能看到公开信息（详细信息被隐藏）\n4. 每个条目显示匹配度评估\n5. 点击查看匹配理由\n\n## 人类质询点\n- 公开信息是否真的不包含私密内容？\n- 匹配度评估准确吗？', 1, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (683, 'US-AGENT-013~edge', 50, '异常：尝试查看详细信息', 'edge_case', '1. 点击尝试查看详细信息，应触发披露流程或被拒绝\n2. 通过 API 直接请求详细信息接口，应返回 403', 2, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (684, 'US-AGENT-015~func', 51, '用户在匹配过程中随时退出', 'functional', '## 前置准备\n- 进入任意匹配流程（推荐列表或四人群聊）\n\n## 验收步骤\n1. 在匹配列表页点击退出\n2. 验证：匹配流程终止\n3. Agent 礼貌结束对话\n4. 在四人群聊中点击退出\n5. 验证：群聊状态更新，对方收到通知\n\n## 人类质询点\n- 退出流程顺畅吗？有确认步骤吗？\n- 退出后对方收到的通知是否礼貌？\n- 退出后能否重新加入？', 1, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (685, 'US-AGENT-015~edge', 51, '异常：频繁退出加入', 'edge_case', '1. 退出后立即重新加入，是否允许\n2. 频繁退出加入（5次以内），是否有限制\n3. 退出后匹配数据是否保留', 2, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (686, 'US-AGENT-016~func', 52, '用户在对话界面举报不当行为', 'functional', '## 前置准备\n- 进入四人群聊或对话界面\n\n## 验收步骤\n1. 在对话界面找到举报入口\n2. 选择举报类型\n3. 上传证据（消息截图等）\n4. 提交举报\n5. 验证：举报已提交并收到确认\n\n## 人类质询点\n- 举报入口好找吗？\n- 举报类型分类清楚吗？\n- 举报后多久有反馈？', 1, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (687, 'US-AGENT-016~edge', 52, '异常：恶意举报', 'edge_case', '1. 尝试举报不存在的消息，应阻止\n2. 短时间内频繁举报，是否触发审核\n3. 举报后撤销，是否支持', 2, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (688, 'US-AGENT-017~func', 53, '用户注销某场景的 Agent', 'functional', '## 前置准备\n- 用户有多个场景的 Agent\n\n## 验收步骤\n1. 进入 Agent 管理页面\n2. 选择一个场景的 Agent\n3. 点击注销\n4. 确认注销\n5. 验证：该场景 Agent 已注销\n6. 验证：历史交易记录仍保留\n\n## 人类质询点\n- 注销确认流程清楚吗？有二次确认吗？\n- 历史交易记录真的保留了吗？\n- 注销后能否重新创建同场景 Agent？', 1, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (689, 'US-AGENT-017~edge', 53, '异常：注销后重新创建', 'edge_case', '1. 注销后立即重新创建同场景 Agent，是否允许\n2. 注销所有场景的 Agent 后，账号是否仍然可用\n3. 注销过程中有进行中的匹配，如何处理', 2, NULL, NULL, NULL, NULL, NULL, 'pending', 'pending');
