INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (143, 'ISSUE-F001~c9', NULL, replace('配置移动端资源文件和环境变量:\n- assets/ 目录下 icon.png, splash.png, adaptive-icon.png, favicon.png 存在且为有效图片\n- 移动端 EXPO_PUBLIC_API_URL 配置正确指向后端服务\n- 后端 CORS 配置允许移动端开发服务器访问','\n', char(10)), 'functional', 'manual_verify', 1, 'not_needed', NULL, NULL, NULL, NULL, 'pending', 'pending');
