INSERT OR IGNORE INTO 'acceptance_criteria'('id', 'slug', 'story_id', 'description', 'criteria_type', 'verification_method', 'priority', 'coverage_ai', 'coverage_e2e', 'coverage_integration', 'coverage_manual', 'coverage_unit', 'ai_status', 'human_status') VALUES (145, 'ISSUE-A001~c1', NULL, replace('实现注册接口:\n- 手机号/邮箱注册\n- 密码强度验证\n- 验证码发送和校验\n- 用户唯一性检查\n','\n', char(10)), 'functional', '{''ai'': {''context_files'': [''apps/server/src/routes/auth.ts'', ''apps/server/src/services/authService.ts''], ''prompt'': ''检查用户注册 API 实现，验证有 /api/v1/auth/register 端点，包含手机号/邮箱验证和密码加密''}}', 1, 'sufficient', 'required', 'required', 'not_needed', 'required', 'pending', 'pending');
