INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (18, 'NP-18', 83, 1055, 'reviewed-to-implemented', 'test_coverage', 'critical', 'Incomplete @bridgeai/shared mock — missing AgentAdRole, AgentDateRole, AgentJobRole, HandoffErrorCode, ProfileCompletionResult exports. consumerDemand.test.ts has 17 test failures because AgentAdRole.CONSUMER is undefined at runtime.', 'grep AgentAdRole apps/server/src/__mocks__/@bridgeai/shared.ts returns 0 matches. AgentAdRole is defined in packages/shared/src/types/agentAdConsumer.ts. consumerDemand.test.ts error: ''Cannot read properties of undefined (reading CONSUMER)'' at consumerDemandService.ts:807', 'Add missing exports to apps/server/src/__mocks__/@bridgeai/shared.ts: AgentAdRole, AgentDateRole, AgentJobRole, HandoffErrorCode, ProfileCompletionResult, UpdateL1ProfileRequest.', 'apps/server/src/__mocks__/@bridgeai/shared.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:48:10.317836', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (19, 'NP-19', 83, 1055, 'reviewed-to-implemented', 'runtime_behavior', 'warning', 'Module-level setInterval/setTimeout in ddosProtection.ts (line 187) and securityMonitor.ts (line 178) cause Jest open handle warnings. While forceExit:true handles this, tests importing these modules get noisy timeout errors.', 'Jest output shows: ''Timeout at Object.<anonymous> (src/middleware/ddosProtection.ts:187:1)'' and ''Timeout at initializeSecurityMonitoring (src/services/securityMonitor.ts:178:5)''. Tests pass but generate handle leak warnings.', 'Either mock these modules in tests that import them transitively, or add jest.useFakeTimers() in setup.ts to suppress timer-related handles.', 'apps/server/src/middleware/ddosProtection.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:48:10.318484', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (20, 'NP-20', 83, 1055, 'reviewed-to-implemented', 'code_quality', 'info', 'ts-jest deprecation warning: ''isolatedModules'' config option in jest.config.js is deprecated and will be removed in ts-jest v30.0.0. Should be moved to tsconfig.json.', 'ts-jest[config] (WARN): The ts-jest config option isolatedModules is deprecated and will be removed in v30.0.0. Please use isolatedModules: true in tsconfig.json instead.', 'Add isolatedModules: true to apps/server/tsconfig.json compilerOptions and remove the ts-jest isolatedModules config from jest.config.js.', 'apps/server/jest.config.js', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:48:10.318996', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (21, 'NP-21', 78, 1060, 'reviewed-to-implemented', 'code_quality', 'critical', 'handoffAuth.test.ts still has broken import paths (../../src/ prefix) - RBAC commit only partially fixed test imports', 'Cannot find module ../../src/services/rbacService from src/middleware/__tests__/handoffAuth.test.ts. Lines 17-18 use ../../src/middleware/handoffAuth and ../../src/services/rbacService. Lines 21,29 jest.mock() calls also use ../../src/ paths. Commit message says Fix test file import paths but only fixed rbac.test.ts and rbacService.test.ts, missed handoffAuth.test.ts and socket.test.ts. TypeScript error: TS2307 Cannot find module ../../src/services/rbacService. Test FAIL: 4 test suites affected.', 'Change imports in handoffAuth.test.ts from ../../src/ to ../../ paths: line 17 → ../handoffAuth, line 18 → ../../services/rbacService, lines 21,29 → ../../services/rbacService and ../requestContext', 'apps/server/src/middleware/__tests__/handoffAuth.test.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 09:07:05.269610', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (22, 'NP-22', 78, 1060, 'reviewed-to-implemented', 'consistency', 'warning', 'Two requireRole implementations with same signature but different behavior - auth.ts (sync, JWT-based) vs rbac.ts (async, DB-based)', 'src/middleware/auth.ts:149 exports requireRole checking req.user.role (single JWT field, sync). src/middleware/rbac.ts:18 exports requireRole querying rbacService.getUserRoles() from DB (async). admin/index.ts:14 uses auth.ts version for general admin routes. admin/rbac.ts:11 uses rbac.ts version for RBAC management routes. JWT-based check can become stale if user role changes between logins.', 'Unify on the DB-based requireRole from rbac.ts for all admin routes, or rename auth.ts version to requireRoleJWT to disambiguate. The JWT-based version can give stale results when roles change.', 'apps/server/src/middleware/auth.ts:149, apps/server/src/middleware/rbac.ts:18', NULL, 'open', NULL, NULL, NULL, '2026-04-19 09:07:05.270340', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (1, 'NP-1', 92, 1049, 'reviewed-to-implemented', 'code_quality', 'critical', '3 types missing from types/chat.ts: ParticipantStatusInfo, ParticipantIdentity, UserOnlineStatus. All new components import these types from types/chat.ts but they are never defined there. TypeScript compiler reports 8 TS2305 errors across 6 source files.', 'tsc output shows 8 errors: IdentityBadge.tsx, ParticipantStatusBar.tsx, ParticipantStatusCard.tsx(2), StatusChangeNotification.tsx, UserStatusIndicator.tsx, plus 2 in test files. All TS2305 Module has no exported member.', 'Add missing types to types/chat.ts: ParticipantIdentity (agent|human), UserOnlineStatus (online|offline|away), ParticipantStatusInfo interface.', 'apps/mobile/src/types/chat.ts', NULL, 'adopted', 'fix_inline', NULL, NULL, '2026-04-19 08:22:58.928945', '2026-04-19 10:54:41.004117');
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (2, 'NP-2', 92, 1049, 'reviewed-to-implemented', 'test_coverage', 'critical', 'SenderIndicator.tsx (317 lines, 2 exported components with complex animation logic) has no test file at all.', 'Component exists at apps/mobile/src/components/Chat/SenderIndicator.tsx but no test file at apps/mobile/src/components/Chat/__tests__/SenderIndicator.test.tsx', 'Create SenderIndicator.test.tsx covering: each SenderType variant, transition with HandoffStatus states, SenderChangeIndicator, animate=false fallback.', 'apps/mobile/src/components/Chat/SenderIndicator.tsx', NULL, 'adopted', 'fix_inline', NULL, NULL, '2026-04-19 08:22:58.930046', '2026-04-19 10:54:41.004835');
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (3, 'NP-3', 92, 1049, 'reviewed-to-implemented', 'code_quality', 'warning', 'StatusChangeNotification receives fromIdentity prop but never uses it. Aliased to _fromIdentity on line 42, never referenced.', 'Line 42: fromIdentity: _fromIdentity - unused variable', 'Either remove fromIdentity prop or use it to show contextual transition info.', 'apps/mobile/src/components/Chat/StatusChangeNotification.tsx:42', NULL, 'adopted', 'fix_inline', NULL, NULL, '2026-04-19 08:22:58.930655', '2026-04-19 10:54:41.005171');
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (4, 'NP-4', 92, 1049, 'reviewed-to-implemented', 'code_quality', 'warning', 'StatusChangeNotification uses 5 hardcoded hex colors (#FEF3C7, #FDE68A, #92400E) instead of theme tokens. All other components correctly use theme.colors.*.', 'Styles lines 98-128: backgroundColor #FEF3C7, borderColor #FDE68A, color #92400E (3x)', 'Add notification colors to theme or use existing semantic tokens.', 'apps/mobile/src/components/Chat/StatusChangeNotification.tsx', NULL, 'adopted', 'fix_inline', NULL, NULL, '2026-04-19 08:22:58.931160', '2026-04-19 10:54:41.005471');
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (5, 'NP-5', 92, 1049, 'reviewed-to-implemented', 'verification', 'warning', 'OnlineStatus.test.tsx was modified in this commit (clearAllMocks->resetAllMocks, container->UNSAFE_root) but still fails 10/10 with host component detection error from @testing-library/react-native.', 'git diff shows changes. Test output: 10 failed, 10 total. Error: Unable to find element with testID text during host component detection.', 'Fix was incomplete. Real issue is @testing-library/react-native mock compatibility. Fix mock or skip tests as tech debt.', 'apps/mobile/src/__tests__/components/OnlineStatus.test.tsx', NULL, 'dismissed', NULL, NULL, NULL, '2026-04-19 08:22:58.931620', '2026-04-19 10:54:41.005749');
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (6, 'NP-6', 84, 1050, 'reviewed-to-implemented', 'test_coverage', 'critical', '33/112 integration tests fail (3/6 suites): auth.integration, user.integration, error.integration. Tests assert against API endpoints and response formats that do not match the actual server implementation.', 'Test output: FAIL auth.integration.test.ts, FAIL user.integration.test.ts, FAIL error.integration.test.ts. Tests: 33 failed, 79 passed, 112 total.', 'Fix test assertions to match actual API routes and response format, OR implement the expected API endpoints.', 'apps/server/src/tests/integration/', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:32:00.816237', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (7, 'NP-7', 84, 1050, 'reviewed-to-implemented', 'test_coverage', 'critical', 'Tests reference /api/v1/auth/register endpoint which does not exist. 4 auth tests test registration (success, invalid email, weak password, duplicate email) but the auth route only has /login, /refresh, /logout, /logout-all, /me.', 'grep router.post / routes/v1/auth.ts shows only /login, /refresh, /logout, /logout-all. ApiPaths.auth.register = /api/v1/auth/register is defined in helpers but no route handles it.', 'Either implement POST /api/v1/auth/register route or remove/update the registration tests.', 'apps/server/src/tests/integration/auth.integration.test.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:32:00.817324', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (8, 'NP-8', 84, 1050, 'reviewed-to-implemented', 'code_quality', 'critical', 'createTestUser helper stores plaintext password as passwordHash instead of bcrypt hash. Login route uses bcrypt.compare() which always returns false for plaintext, causing all login-dependent tests to fail with 401.', 'auth.ts:151 stores passwordHash: user.password || "hashed-password" (plaintext). auth route uses bcrypt.compare(password, user.passwordHash) which fails for non-hashed values.', 'Use bcrypt.hash() to hash the password before storing: passwordHash: await bcrypt.hash(user.password, 10)', 'apps/server/src/tests/helpers/auth.ts:151', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:32:00.817891', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (9, 'NP-9', 84, 1050, 'reviewed-to-implemented', 'test_coverage', 'critical', 'User integration tests expect admin CRUD routes at /api/v1/users/:id and /api/v1/users (list), but actual user routes use /me pattern (GET/PUT/DELETE /api/v1/users/me). No admin-only list endpoint exists.', 'Tests call ApiPaths.users.list (/api/v1/users) and ApiPaths.users.detail(id) (/api/v1/users/:id). Actual routes: /me, /privacy, /avatar, /password, /phone, /email, /devices, /block.', 'Update tests to match actual /me-based user API routes, or implement admin CRUD endpoints.', 'apps/server/src/tests/integration/user.integration.test.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:32:00.818368', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (10, 'NP-10', 84, 1050, 'reviewed-to-implemented', 'verification', 'warning', 'Auth login test expects body.data.accessToken but actual API response structure is body.data.tokens.accessToken (tokens nested under data.tokens, not directly under data).', 'Login route returns ApiResponse.success({user: {...}, tokens: {accessToken, refreshToken, expiresIn}}). Test asserts body.data.accessToken but should be body.data.tokens.accessToken.', 'Update test assertions: body.data.tokens.accessToken instead of body.data.accessToken.', 'apps/server/src/tests/integration/auth.integration.test.ts:92-94', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:32:00.818814', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (11, 'NP-11', 84, 1050, 'reviewed-to-implemented', 'verification', 'warning', 'validateErrorResponse returns false for login empty body test despite status being 400. The error response format from the API may not match what the validator expects (possibly middleware interference in the response pipeline).', 'Test: Request.post(login, {}) returns status 400 (correct) but validateErrorResponse(response) returns false. ApiResponse.error format: {success:false, message:string, errorCode:string, meta:{statusCode:number}}.', 'Debug the actual response body in the failing test. The security middleware pipeline (ddosProtection, ipFilter, securityProtection) may modify the error response format.', 'apps/server/src/tests/helpers/validator.ts:120-127', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:32:00.819241', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (12, 'NP-12', 84, 1050, 'reviewed-to-implemented', 'runtime_behavior', 'warning', 'Multiple setInterval/setTimeout calls in middleware (ddosProtection, rateLimiter, clarificationService, securityMonitor) prevent Jest from exiting cleanly, causing open handle warnings. jest.config has forceExit:true as workaround.', 'Jest output: 4 open handles from setInterval in ddosProtection.ts:187, rateLimiter.ts:65, clarificationService.ts:97, securityMonitor.ts:178.', 'Use a shared timer manager that can be cleaned up in test teardown, or lazy-initialize timers only when not in test environment.', 'apps/server/src/middleware/ddosProtection.ts:187', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:32:00.819641', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (13, 'NP-13', 77, 1054, 'reviewed-to-implemented', 'consistency', 'critical', 'Dual data model: CreditScoreService class methods use new CreditScore/CreditHistory/CreditFactor models, but standalone functions updateCreditScore() and recalculateCreditScore() use the old CreditRecord model. Data splits across two incompatible schemas.', 'creditScoreService.ts line 630: prisma.creditRecord.create(), line 697: prisma.creditRecord.create(). vs class methods line 289: prisma.creditScore.findUnique(), line 352: prisma.creditHistory.create(). grep shows 2 usages of prisma.creditRecord vs 14 usages of prisma.creditScore/creditHistory/creditFactor.', 'Migrate standalone functions updateCreditScore() and recalculateCreditScore() to use the new CreditScore/CreditHistory models instead of CreditRecord. Or remove the standalone functions and use the class methods throughout.', 'apps/server/src/services/creditScoreService.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:44:04.149605', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (14, 'NP-14', 77, 1054, 'reviewed-to-implemented', 'consistency', 'critical', 'Shared package CreditLevel type uses "average" but server uses "general". Also score thresholds differ: shared has 800/600/400/0 vs server has 900/750/600/0. Mobile/frontend using shared types will show wrong levels and thresholds.', 'packages/shared/src/types/credit.ts line 15: CreditLevel type = excellent|good|average|poor. Line 21: average: {min:400,max:599}. apps/server/src/types/credit.ts line 11: GENERAL=general, 600-749. apps/server/src/config/creditLevels.ts: EXCELLENT 900-1000, GOOD 750-899, GENERAL 600-749, POOR 0-599.', 'Align shared CREDIT_LEVEL_THRESHOLDS and CreditLevel type with server definitions. Change "average" to "general" and update thresholds to 900/750/600/0.', 'packages/shared/src/types/credit.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:44:04.150876', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (15, 'NP-15', 77, 1054, 'reviewed-to-implemented', 'verification', 'critical', 'POST /api/v1/credit/recalculate for all-users is a no-op: returns fake success "Recalculation job started" without triggering any job. AC4 requires this endpoint to recalculate all users credit scores.', 'apps/server/src/routes/credit.ts line 193-202: else branch returns {message: "Recalculation job started for all users", note: "This may take a while"} but only has a TODO comment. No actual job is triggered.', 'Implement the batch recalculation by calling creditUpdateJob or iterating users with creditScoreService.updateCreditScore().', 'apps/server/src/routes/credit.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:44:04.151397', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (16, 'NP-16', 77, 1054, 'reviewed-to-implemented', 'code_quality', 'warning', 'replyRateBonus hardcoded to 0 with TODO comment. Reply rate tracking is not implemented in recalculateCreditScore.', 'creditScoreService.ts line 688: const replyRateBonus = 0; // TODO: Implement reply tracking', 'Implement reply tracking to calculate the bonus, or remove the variable and add a comment explaining this is intentionally deferred.', 'apps/server/src/services/creditScoreService.ts', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:44:04.151850', NULL);
INSERT OR IGNORE INTO 'nitpick_findings'('id', 'slug', 'issue_id', 'task_id', 'transition', 'category', 'severity', 'description', 'evidence', 'recommendation', 'file_path', 'line_range', 'status', 'disposition', 'related_ac_id', 'duplicate_of', 'created_at', 'resolved_at') VALUES (17, 'NP-17', 83, 1055, 'reviewed-to-implemented', 'test_coverage', 'critical', 'class-validator dependency missing from apps/server/package.json — imported by src/config/security.ts but not installed, causing 8 test suites to cascade-fail with ''Cannot find module class-validator''. Affected tests: encryption, keyManagement, mask, pii, and others importing security.ts.', 'grep class-validator apps/server/package.json returns empty. pnpm --filter server test 2>&1 shows 8 suites failing with ''Cannot find module class-validator from src/config/security.ts''. Example cascade: security.ts -> mask.ts -> pii.test.ts', 'Add class-validator and class-transformer to apps/server/package.json dependencies and run pnpm install.', 'apps/server/package.json', NULL, 'open', NULL, NULL, NULL, '2026-04-19 08:48:10.316476', NULL);
